#include <vector>
#include <algorithm>
#include <deque>
#include <queue>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    int n = nums.size();
    priority_queue<pair<long long, pair<int, int>>> pq;

    // Precompute all possible subarrays and their values
    for (int i = 0; i < n; ++i) {
        deque<int> min_q, max_q;
        for (int j = i; j < n; ++j) {
            // Maintain min deque
            while (!min_q.empty() && nums[j] < nums[min_q.back()]) {
                min_q.pop_back();
            }
            min_q.push_back(j);

            // Maintain max deque
            while (!max_q.empty() && nums[j] > nums[max_q.back()]) {
                max_q.pop_back();
            }
            max_q.push_back(j);

            // Remove elements out of current window [i..j]
            while (min_q.front() < i) {
                min_q.pop_front();
            }
            while (max_q.front() < i) {
                max_q.pop_front();
            }

            long long current_val = nums[max_q.front()] - nums[min_q.front()];
            pq.push({current_val, {i, j}});
        }
    }

    long long total = 0;
    while (k > 0 && !pq.empty()) {
        auto top = pq.top();
        pq.pop();
        total += top.first;
        --k;
    }

    return total;
}
