long long solve(vector<long long> nums, long long k) {
    int n = nums.size();
    vector<long long> max_values;
    vector<long long> min_values;

    // We'll use monotonic queues to find all possible subarrays' max and min differences
    for (int i = 0; i < n; ++i) {
        deque<int> max_q, min_q;
        for (int j = i; j < n; ++j) {
            // Maintain the max deque
            while (!max_q.empty() && nums[j] >= nums[max_q.back()]) {
                max_q.pop_back();
            }
            max_q.push_back(j);

            // Maintain the min deque
            while (!min_q.empty() && nums[j] <= nums[min_q.back()]) {
                min_q.pop_back();
            }
            min_q.push_back(j);

            // The current max and min are at the front of the deques
            long long current_max = nums[max_q.front()];
            long long current_min = nums[min_q.front()];
            max_values.push_back(current_max - current_min);
        }
    }

    // Sort the differences in descending order
    sort(max_values.begin(), max_values.end(), greater<long long>());

    // Sum the top k values
    long long total = 0;
    for (int i = 0; i < k && i < max_values.size(); ++i) {
        total += max_values[i];
    }

    return total;
