    priority_queue<long long> max_heap;

    for (int l = 0; l < n; ++l) {
        long long current_max = nums[l];
        long long current_min = nums[l];
        for (int r = l; r < n; ++r) {
            current_max = max(current_max, nums[r]);
            current_min = min(current_min, nums[r]);
            max_heap.push(current_max - current_min);
        }
    }

    long long result = 0;
    while (k > 0 && !max_heap.empty()) {
        result += max_heap.top();
        max_heap.pop();
        --k;
    }

    return result;
